CREATE TABLE IF NOT EXISTS`picking` (
  `IDPicking` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `ErqId` varchar(40) NOT NULL,
  `Station` varchar(15) DEFAULT NULL,
  `Component` char(1) DEFAULT NULL,
  `P-Picking` double DEFAULT NULL,
  `P-Quality` tinyint(4) DEFAULT NULL,
  `P-Arrival` char(1) DEFAULT NULL,
  `P-Polarity` char(1) DEFAULT NULL,
  `S-Picking` double DEFAULT NULL,
  `S-Quality` tinyint(4) DEFAULT NULL,
  `S-Arrival` char(1) DEFAULT NULL,
  `S-Polarity` char(1) DEFAULT NULL,
  `Coda` varchar(15) DEFAULT NULL,
  `S-Hypo` varchar(15) DEFAULT NULL,
  `TracePos` int(11) DEFAULT NULL,
  `CodaPos` int(11) DEFAULT NULL,
  `PTime` double DEFAULT NULL,
  `STime` double DEFAULT NULL,
  `mag_used` bit(1) DEFAULT NULL,
  `ml` double DEFAULT NULL,
  PRIMARY KEY (`IDPicking`)
) ENGINE=InnoDB AUTO_INCREMENT=423046 DEFAULT CHARSET=latin1;

